for (const [prefix, extra] of Object.entries(expansions)) {
  const index = content.findIndex((item) => item.type === "h2" && item.text.startsWith(prefix));
  if (index !== -1) {
    content.splice(index + 1, 0, ...extra.map((text) => p(text)));
  }
}

