for (const [prefix, extra] of Object.entries(finalExpansions)) {
  const index = content.findIndex((item) => item.type === "h2" && item.text.startsWith(prefix));
  if (index !== -1) {
    content.splice(index + 1, 0, p(extra));
  }
}

function itemByCaption(caption) {
  return content.find((item) => item.caption === caption);
}

function replaceRange(startText, endTextExclusive, replacement) {
  const startIndex = content.findIndex((item) => item.type === "h1" && item.text === startText);
  const endIndex = content.findIndex((item, index) => index > startIndex && item.type === "h1" && item.text === endTextExclusive);
  if (startIndex === -1 || endIndex === -1 || endIndex <= startIndex) {
    throw new Error(`Cannot replace range: ${startText} -> ${endTextExclusive}`);
  }
  content.splice(startIndex, endIndex - startIndex, ...replacement);
}

