function lowerAfterSemicolon(text) {
  if (!text) return text;
  const first = text[0];
  return /[А-ЯЁ]/.test(first) ? first.toLowerCase() + text.slice(1) : text;
}

function mergeNearbyParagraphs(startPrefix, endPrefix) {
  const startIndex = content.findIndex((item) => item.type === "h1" && item.text.startsWith(startPrefix));
  const endIndex = content.findIndex((item, index) => index > startIndex && item.type === "h1" && item.text.startsWith(endPrefix));
  if (startIndex === -1 || endIndex === -1 || endIndex <= startIndex) return;

  let mergedInSection = 0;
  for (let i = startIndex + 1; i < endIndex - 1; i += 1) {
    const current = content[i];
    const next = content[i + 1];
    if (current.type === "h2") {
      mergedInSection = 0;
      continue;
    }
    if (!current || !next || current.type !== "p" || next.type !== "p") continue;
    if (current.text.startsWith("[") || next.text.startsWith("[")) continue;
    if (/рисунк|таблиц/i.test(current.text) || /рисунк|таблиц/i.test(next.text)) continue;
    if (current.text.length + next.text.length > 1150) continue;
    if (mergedInSection >= 2) continue;

    current.text = current.text.replace(/[.!?]\s*$/, "") + "; " + lowerAfterSemicolon(next.text);
    content.splice(i + 1, 1);
    mergedInSection += 1;
  }
}

function insertBeforeHeading(headingPrefix, text) {
  const index = content.findIndex((item) => item.type === "h2" && item.text.startsWith(headingPrefix));
  if (index === -1) {
    throw new Error(`Cannot insert note before heading: ${headingPrefix}`);
  }
  content.splice(index, 0, p(text));
}

function insertAfterHeadingIntro(headingPrefix, paragraphs) {
  const index = content.findIndex((item) => item.type === "h2" && item.text.startsWith(headingPrefix));
  if (index === -1) {
    throw new Error(`Cannot insert after heading intro: ${headingPrefix}`);
  }
  let insertIndex = index + 1;
  if (content[insertIndex] && content[insertIndex].type === "p") {
    insertIndex += 1;
  }
  content.splice(insertIndex, 0, ...paragraphs.map((text) => p(text)));
}

