function insertParagraphsBeforeHeading(headingPrefix, paragraphs) {
  const index = content.findIndex((item) => item.type === "h2" && item.text.startsWith(headingPrefix));
  if (index === -1) {
    throw new Error(`Cannot insert paragraphs before heading: ${headingPrefix}`);
  }
  content.splice(index, 0, ...paragraphs.map((text) => p(text)));
}

