function h1(text) { return { type: "h1", text }; }
function h2(text) { return { type: "h2", text }; }
function p(text) { return { type: "p", text }; }
function img(file, caption) { return { type: "img", file, caption }; }
function table(caption, rows) { return { type: "table", caption, rows }; }
function src(text) { return { type: "src", text }; }

function paragraph(text, style = "Normal") {
  const stylePart = style !== "Normal" ? `<w:pStyle w:val="${style}"/>` : "";
  const jc = style === "Caption" ? `<w:jc w:val="center"/>` : "";
  const noIndent = style === "Heading1" || style === "Heading2" || style === "Caption" || style === "Source";
  const ind = noIndent ? "" : `<w:ind w:firstLine="709"/>`;
  const spacing = `<w:spacing w:line="360" w:lineRule="auto" w:after="${style === "Heading1" ? 240 : 120}"/>`;
  const bold = style === "Heading1" || style === "Heading2" ? "<w:b/>" : "";
  return `<w:p><w:pPr>${stylePart}${spacing}${ind}${jc}</w:pPr><w:r><w:rPr>${bold}<w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr><w:t xml:space="preserve">${esc(text)}</w:t></w:r></w:p>`;
}

function tableXml(item) {
  const rows = item.rows.map((row, rowIndex) => {
    const cells = row.map((cell) => {
      const bold = rowIndex === 0 ? "<w:b/>" : "";
      return `<w:tc><w:tcPr><w:tcW w:w="2400" w:type="dxa"/><w:tcMar><w:top w:w="80" w:type="dxa"/><w:left w:w="80" w:type="dxa"/><w:bottom w:w="80" w:type="dxa"/><w:right w:w="80" w:type="dxa"/></w:tcMar></w:tcPr><w:p><w:pPr><w:spacing w:line="300" w:lineRule="auto" w:after="60"/></w:pPr><w:r><w:rPr>${bold}<w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="24"/><w:szCs w:val="24"/></w:rPr><w:t xml:space="preserve">${esc(cell)}</w:t></w:r></w:p></w:tc>`;
    }).join("");
    return `<w:tr>${cells}</w:tr>`;
  }).join("");
  return [
    paragraph(item.caption, "Caption"),
    `<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/><w:tblBorders><w:top w:val="single" w:sz="6" w:space="0" w:color="444444"/><w:left w:val="single" w:sz="6" w:space="0" w:color="444444"/><w:bottom w:val="single" w:sz="6" w:space="0" w:color="444444"/><w:right w:val="single" w:sz="6" w:space="0" w:color="444444"/><w:insideH w:val="single" w:sz="4" w:space="0" w:color="666666"/><w:insideV w:val="single" w:sz="4" w:space="0" w:color="666666"/></w:tblBorders></w:tblPr>${rows}</w:tbl>`,
  ].join("");
}

function imageXml(item, relId, index) {
  const imagePath = path.join(ASSETS, item.file);
  const { cx, cy } = scaledImageExtent(imagePath, item.file.startsWith("screenshot") ? 15.4 : 15.8);
  return `<w:p><w:pPr><w:jc w:val="center"/><w:spacing w:after="120"/></w:pPr><w:r><w:drawing><wp:inline distT="0" distB="0" distL="0" distR="0"><wp:extent cx="${cx}" cy="${cy}"/><wp:effectExtent l="0" t="0" r="0" b="0"/><wp:docPr id="${index}" name="Picture ${index}"/><wp:cNvGraphicFramePr><a:graphicFrameLocks noChangeAspect="1"/></wp:cNvGraphicFramePr><a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:nvPicPr><pic:cNvPr id="${index}" name="${esc(item.file)}"/><pic:cNvPicPr/></pic:nvPicPr><pic:blipFill><a:blip r:embed="${relId}"/><a:stretch><a:fillRect/></a:stretch></pic:blipFill><pic:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="${cx}" cy="${cy}"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom></pic:spPr></pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p>${paragraph(item.caption, "Caption")}`;
}

function buildDocumentXml() {
  let body = "";
  const rels = [];
  let imgIndex = 1;
  for (const item of content) {
    if (item.type === "h1") body += paragraph(item.text, "Heading1");
    if (item.type === "h2") body += paragraph(item.text, "Heading2");
    if (item.type === "p") body += paragraph(item.text, "Normal");
    if (item.type === "src") body += paragraph(item.text, "Source");
    if (item.type === "table") body += tableXml(item);
    if (item.type === "img") {
      const relId = `rIdImg${imgIndex}`;
      rels.push({ id: relId, file: item.file });
      body += imageXml(item, relId, imgIndex);
      imgIndex += 1;
    }
  }
  body += `<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1134" w:right="850" w:bottom="1134" w:left="1701" w:header="708" w:footer="708" w:gutter="0"/></w:sectPr>`;
  return {
    documentXml: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:document xmlns:wpc="http://schemas.microsoft.com/office/word/2010/wordprocessingCanvas" xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math" xmlns:v="urn:schemas-microsoft-com:vml" xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture" xmlns:wp14="http://schemas.microsoft.com/office/word/2010/wordprocessingDrawing" xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing" xmlns:w10="urn:schemas-microsoft-com:office:word" xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:w14="http://schemas.microsoft.com/office/word/2010/wordml" xmlns:wpg="http://schemas.microsoft.com/office/word/2010/wordprocessingGroup" xmlns:wpi="http://schemas.microsoft.com/office/word/2010/wordprocessingInk" xmlns:wne="http://schemas.microsoft.com/office/word/2006/wordml" xmlns:wps="http://schemas.microsoft.com/office/word/2010/wordprocessingShape" mc:Ignorable="w14 wp14"><w:body>${body}</w:body></w:document>`,
    rels,
  };
}

function writePackage() {
  rmrf(BUILD);
  mkdirp(path.join(BUILD, "_rels"));
  mkdirp(path.join(BUILD, "word", "_rels"));
  mkdirp(path.join(BUILD, "word", "media"));
  mkdirp(path.join(BUILD, "docProps"));

  const { documentXml, rels } = buildDocumentXml();
  fs.writeFileSync(path.join(BUILD, "word", "document.xml"), documentXml, "utf8");

  for (const rel of rels) {
    fs.copyFileSync(path.join(ASSETS, rel.file), path.join(BUILD, "word", "media", rel.file));
  }

  const imageRels = rels.map((rel) => `<Relationship Id="${rel.id}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="media/${esc(rel.file)}"/>`).join("");
  fs.writeFileSync(path.join(BUILD, "word", "_rels", "document.xml.rels"), `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rIdStyles" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/><Relationship Id="rIdSettings" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/settings" Target="settings.xml"/>${imageRels}</Relationships>`, "utf8");
  fs.writeFileSync(path.join(BUILD, "_rels", ".rels"), `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/><Relationship Id="rId2" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/><Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/></Relationships>`, "utf8");
  fs.writeFileSync(path.join(BUILD, "[Content_Types].xml"), `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Default Extension="png" ContentType="image/png"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/><Override PartName="/word/settings.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.settings+xml"/><Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-package.core-properties+xml"/><Override PartName="/docProps/app.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/></Types>`, "utf8");
  fs.writeFileSync(path.join(BUILD, "word", "styles.xml"), stylesXml(), "utf8");
  fs.writeFileSync(path.join(BUILD, "word", "settings.xml"), `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:settings xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:zoom w:percent="100"/><w:defaultTabStop w:val="708"/></w:settings>`, "utf8");
  fs.writeFileSync(path.join(BUILD, "docProps", "core.xml"), `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:dcmitype="http://purl.org/dc/dcmitype/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>Разработка приложения для оценки знаний студентов</dc:title><dc:creator>Пеньшин Г. Р.</dc:creator><cp:lastModifiedBy>Пеньшин Г. Р.</cp:lastModifiedBy><dcterms:created xsi:type="dcterms:W3CDTF">2026-05-16T00:00:00Z</dcterms:created><dcterms:modified xsi:type="dcterms:W3CDTF">2026-05-16T00:00:00Z</dcterms:modified></cp:coreProperties>`, "utf8");
  fs.writeFileSync(path.join(BUILD, "docProps", "app.xml"), `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties" xmlns:vt="http://schemas.openxmlformats.org/officeDocument/2006/docPropsVTypes"><Application>Microsoft Word</Application></Properties>`, "utf8");

  if (fs.existsSync(OUT)) fs.unlinkSync(OUT);
  writeZipFromDirectory(BUILD, OUT);
}

function crc32(buffer) {
  let crc = 0xffffffff;
  for (const byte of buffer) {
    crc = (crc >>> 8) ^ CRC_TABLE[(crc ^ byte) & 0xff];
  }
  return (crc ^ 0xffffffff) >>> 0;
}

const CRC_TABLE = (() => {
  const table = new Uint32Array(256);
  for (let i = 0; i < 256; i += 1) {
    let c = i;
    for (let k = 0; k < 8; k += 1) {
      c = c & 1 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
    }
    table[i] = c >>> 0;
  }
  return table;
})();

function dosDateTime(date = new Date()) {
  const year = Math.max(1980, date.getFullYear());
  const dosTime = (date.getHours() << 11) | (date.getMinutes() << 5) | Math.floor(date.getSeconds() / 2);
  const dosDate = ((year - 1980) << 9) | ((date.getMonth() + 1) << 5) | date.getDate();
  return { dosTime, dosDate };
}

function listFiles(dir, prefix = "") {
  const entries = [];
  for (const name of fs.readdirSync(dir)) {
    const absolute = path.join(dir, name);
    const relative = prefix ? `${prefix}/${name}` : name;
    const stat = fs.statSync(absolute);
    if (stat.isDirectory()) entries.push(...listFiles(absolute, relative));
    if (stat.isFile()) entries.push({ absolute, relative });
  }
  return entries;
}

function writeZipFromDirectory(sourceDir, outputFile) {
  const files = listFiles(sourceDir).map((file) => ({
    ...file,
    nameBuffer: Buffer.from(file.relative.replace(/\\/g, "/"), "utf8"),
    data: fs.readFileSync(file.absolute),
  }));
  const chunks = [];
  const central = [];
  let offset = 0;
  const { dosTime, dosDate } = dosDateTime(new Date("2026-05-16T00:00:00"));

  for (const file of files) {
    const crc = crc32(file.data);
    const local = Buffer.alloc(30);
    local.writeUInt32LE(0x04034b50, 0);
    local.writeUInt16LE(20, 4);
    local.writeUInt16LE(0x0800, 6);
    local.writeUInt16LE(0, 8);
    local.writeUInt16LE(dosTime, 10);
    local.writeUInt16LE(dosDate, 12);
    local.writeUInt32LE(crc, 14);
    local.writeUInt32LE(file.data.length, 18);
    local.writeUInt32LE(file.data.length, 22);
    local.writeUInt16LE(file.nameBuffer.length, 26);
    local.writeUInt16LE(0, 28);
    chunks.push(local, file.nameBuffer, file.data);

    const c = Buffer.alloc(46);
    c.writeUInt32LE(0x02014b50, 0);
    c.writeUInt16LE(20, 4);
    c.writeUInt16LE(20, 6);
    c.writeUInt16LE(0x0800, 8);
    c.writeUInt16LE(0, 10);
    c.writeUInt16LE(dosTime, 12);
    c.writeUInt16LE(dosDate, 14);
    c.writeUInt32LE(crc, 16);
    c.writeUInt32LE(file.data.length, 20);
    c.writeUInt32LE(file.data.length, 24);
    c.writeUInt16LE(file.nameBuffer.length, 28);
    c.writeUInt16LE(0, 30);
    c.writeUInt16LE(0, 32);
    c.writeUInt16LE(0, 34);
    c.writeUInt16LE(0, 36);
    c.writeUInt32LE(0, 38);
    c.writeUInt32LE(offset, 42);
    central.push(c, file.nameBuffer);
    offset += local.length + file.nameBuffer.length + file.data.length;
  }

  const centralOffset = offset;
  const centralSize = central.reduce((sum, chunk) => sum + chunk.length, 0);
  const end = Buffer.alloc(22);
  end.writeUInt32LE(0x06054b50, 0);
  end.writeUInt16LE(0, 4);
  end.writeUInt16LE(0, 6);
  end.writeUInt16LE(files.length, 8);
  end.writeUInt16LE(files.length, 10);
  end.writeUInt32LE(centralSize, 12);
  end.writeUInt32LE(centralOffset, 16);
  end.writeUInt16LE(0, 20);
  fs.writeFileSync(outputFile, Buffer.concat([...chunks, ...central, end]));
}

function stylesXml() {
  return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:rPrDefault><w:pPrDefault><w:pPr><w:spacing w:line="360" w:lineRule="auto" w:after="120"/></w:pPr></w:pPrDefault></w:docDefaults><w:style w:type="paragraph" w:default="1" w:styleId="Normal"><w:name w:val="Normal"/><w:qFormat/></w:style><w:style w:type="paragraph" w:styleId="Heading1"><w:name w:val="Heading 1"/><w:basedOn w:val="Normal"/><w:next w:val="Normal"/><w:qFormat/><w:pPr><w:keepNext/><w:spacing w:before="240" w:after="240"/><w:outlineLvl w:val="0"/></w:pPr><w:rPr><w:b/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="Heading2"><w:name w:val="Heading 2"/><w:basedOn w:val="Normal"/><w:next w:val="Normal"/><w:qFormat/><w:pPr><w:keepNext/><w:spacing w:before="200" w:after="160"/><w:outlineLvl w:val="1"/></w:pPr><w:rPr><w:b/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="Caption"><w:name w:val="Caption"/><w:basedOn w:val="Normal"/><w:qFormat/><w:rPr><w:sz w:val="24"/><w:szCs w:val="24"/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="Source"><w:name w:val="Source"/><w:basedOn w:val="Normal"/><w:qFormat/><w:pPr><w:spacing w:line="360" w:lineRule="auto" w:after="120"/></w:pPr><w:rPr><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:style></w:styles>`;
}

function verifyText() {
  const text = content
    .map((item) => item.text || item.caption || (item.rows ? item.rows.flat().join(" ") : ""))
    .join("\n")
    .toLowerCase();
  const hits = forbidden.filter((item) => text.includes(item));
  if (hits.length) {
    const contexts = hits.map((item) => {
      const idx = text.indexOf(item);
      return text.slice(Math.max(0, idx - 80), Math.min(text.length, idx + item.length + 80));
    });
    throw new Error(`Forbidden phrases found: ${hits.join(", ")}\n${contexts.join("\n---\n")}`);
  }
}

function verifyAssets() {
  const missing = content
    .filter((item) => item.type === "img")
    .map((item) => item.file)
    .filter((file) => !fs.existsSync(path.join(ASSETS, file)));
  if (missing.length) {
    throw new Error(`Missing assets: ${missing.join(", ")}`);
  }
}

verifyText();
verifyAssets();
writePackage();
console.log(`Created ${OUT}`);
